def find_all(text, pattern):
    n = len(text)
    m = len(pattern)
    if m == 0:
        return []
    if m > n:
        return []
    text_b = text.encode("latin-1") if isinstance(text, str) else text
    pat_b = pattern.encode("latin-1") if isinstance(pattern, str) else pattern
    if m == 1:
        target = pat_b[0]
        return [i for i in range(n) if text_b[i] == target]
    fail = [0] * m
    k = 0
    for i in range(1, m):
        while k > 0 and pat_b[k] \!= pat_b[i]:
            k = fail[k - 1]
        if pat_b[k] == pat_b[i]:
            k += 1
        fail[i] = k
    period = m - fail[m - 1]
    skip = [m] * 256
    for i in range(m - 1):
        skip[pat_b[i]] = m - 1 - i
    last_char = pat_b[m - 1]
    results = []
    append = results.append
    i = m - 1
    while i < n:
        if text_b[i] == last_char and text_b[i - m + 1:i + 1] == pat_b:
            append(i - m + 1)
            i += period
        else:
            i += skip[text_b[i]]
    return results
